import React, { useEffect, useRef } from 'react';

export interface RemoteParticipant {
  stream: MediaStream | null;
  userId: string;
  role: 'broadcaster' | 'viewer';
  hasVideo: boolean;
}

interface VideoGridProps {
  streams: Map<string, RemoteParticipant>;
  localStream?: MediaStream | null;
  localUserId?: string;
  showLocalPlaceholder?: boolean; // Show local tile even when camera is off
}

const VideoTile: React.FC<{
  stream: MediaStream | null;
  name: string;
  isBroadcaster: boolean;
  isLocal?: boolean;
  hasVideo: boolean;
}> = ({ stream, name, isBroadcaster, isLocal, hasVideo }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
    }
  }, [stream]);

  return (
    <div style={styles.tile}>
      {hasVideo && stream ? (
        <video
          ref={videoRef}
          autoPlay
          playsInline
          muted={isLocal}
          style={styles.video}
        />
      ) : (
        <div style={styles.noVideo}>
          <div style={styles.avatar}>{name.charAt(0).toUpperCase()}</div>
          <div style={styles.cameraOff}>Camera Off</div>
        </div>
      )}
      <div style={styles.nameTag}>
        <span style={isBroadcaster ? styles.broadcasterName : styles.viewerName}>
          {name} {isLocal && '(You)'} {isBroadcaster && '★'}
        </span>
      </div>
    </div>
  );
};

export const VideoGrid: React.FC<VideoGridProps> = ({
  streams,
  localStream,
  localUserId,
  showLocalPlaceholder = false,
}) => {
  const showLocalTile = localStream || showLocalPlaceholder;
  const participantCount = streams.size + (showLocalTile ? 1 : 0);

  const getGridColumns = () => {
    if (participantCount <= 1) return 1;
    if (participantCount <= 4) return 2;
    if (participantCount <= 9) return 3;
    return 4;
  };

  return (
    <div style={{ ...styles.grid, gridTemplateColumns: `repeat(${getGridColumns()}, 1fr)` }}>
      {/* Local video first */}
      {showLocalTile && (
        <VideoTile
          stream={localStream ?? null}
          name={localUserId || 'You'}
          isBroadcaster={false}
          isLocal={true}
          hasVideo={!!localStream}
        />
      )}

      {/* Remote videos */}
      {Array.from(streams.entries()).map(([userId, participant]) => (
        <VideoTile
          key={userId}
          stream={participant.stream}
          name={participant.userId}
          isBroadcaster={participant.role === 'broadcaster'}
          hasVideo={participant.hasVideo}
        />
      ))}

      {participantCount === 0 && (
        <div style={styles.emptyState}>
          Waiting for participants...
        </div>
      )}
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  grid: {
    display: 'grid',
    gap: '10px',
    width: '100%',
    minHeight: '300px',
  },
  tile: {
    position: 'relative',
    backgroundColor: '#1a1a1a',
    borderRadius: '8px',
    overflow: 'hidden',
    aspectRatio: '16/9',
  },
  video: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  noVideo: {
    width: '100%',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#2a2a2a',
  },
  avatar: {
    width: '60px',
    height: '60px',
    borderRadius: '50%',
    backgroundColor: '#444',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '24px',
    color: 'white',
    fontWeight: 'bold',
  },
  cameraOff: {
    marginTop: '10px',
    color: '#888',
    fontSize: '12px',
  },
  nameTag: {
    position: 'absolute',
    bottom: '8px',
    left: '8px',
    padding: '4px 8px',
    backgroundColor: 'rgba(0, 0, 0, 0.6)',
    borderRadius: '4px',
  },
  broadcasterName: {
    color: '#ffc107',
    fontSize: '12px',
    fontWeight: 'bold',
  },
  viewerName: {
    color: 'white',
    fontSize: '12px',
  },
  emptyState: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#2a2a2a',
    borderRadius: '8px',
    color: '#888',
    padding: '40px',
    gridColumn: '1 / -1',
  },
};
